form.table:
// Unique identifier.


// Product type. Default is simple. Options (plugins may add new options): simple, grouped, external, variable.

  'simple'


// Product status (post status). Default is publish. Options (plugins may add new options): draft, pending, private and publish.

  'publish'


// Featured product. Default is false.

  IF(tipo_articulo=1,'true','false')


// Catalog visibility. Default is visible. Options: visible (Catalog and search), catalog (Only in catalog), search (Only in search) and hidden (Hidden from all).

  IF(baja_articulo=1, 'hidden','visible')


// Product description.

  ''


// Product regular price.

  @PV:=ROUND(
  CASE WHEN STK_LISTAS.moneda_idvta = STK_ARTICULOS.genmoneda_venta_id THEN IFNULL(STK_LISTADETALLE.stklistadetalle_precioventa,0)
  ELSE
  (CASE  WHEN STK_ARTICULOS.genmoneda_venta_id = 1 THEN
          GEN_FN_COTIZACION(STK_LISTAS.moneda_idvta,current_date()) * IFNULL(STK_LISTADETALLE.stklistadetalle_precioventa,0)
       ELSE
          IFNULL(STK_LISTADETALLE.stklistadetalle_precioventa,0) / GEN_FN_COTIZACION(STK_LISTAS.moneda_idvta,current_date(), 0)
       END)
  END)

  numeric



// Product sale price.

  ROUND(@PV - (@PV * STK_LISTADETALLE.dto_porcentaje / 100), 2)
  numeric        


// Start date of sale price. Date in the YYYY-MM-DD format.

  STK_LISTADETALLE.dto_fechadesde
  varchar


// Sets the sale end date. Date in the YYYY-MM-DD format.

  STK_LISTADETALLE.dto_fechahasta
  varchar


// If the product is virtual. Virtual products are intangible and aren’t shipped. Default is false.

  IF(tipo_articulo=2,'true','false')


// Stock quantity. If is a variable product this value will be used to control stock for all variations, unless you define stock at variation level.

  @STK:=IFNULL(sum(STK_STOCKACTUAL.cantidad_stock),0)


// Controls whether or not the product is listed as “in stock” or “out of stock” on the frontend. Default is true.

  IF(@STK=0,'false','true')


// List of Categories

  STK_RUBROS.nombre_rubro


// List of images

  IF(stkarticulo_foto = '', 'nopict.jpg', CONCAT( id_stkarticulo, '.', SUBSTRING_INDEX(stkarticulo_foto, '.', -1) ) )


// Attributes

   STK_MARCAS.nombre_marca



   nombre_familia



  Description
  varchar






  Publicar
  check
  1



  1
